import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart"; // Your chart component

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data);
      } catch (err) {
        console.error(err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // Fetch every 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count buses by status
  const countByStatus = buses.reduce(
    (acc, bus) => {
      acc[bus.status] = (acc[bus.status] || 0) + 1;
      return acc;
    },
    {}
  );

  const getColor = (status) => {
    switch (status) {
      case "normal":
        return "green";
      case "ghost":
        return "red";
      case "anomaly":
        return "orange";
      default:
        return "blue";
    }
  };

  return (
    <div style={{ position: "relative", height: "100vh", width: "100vw", overflow: "hidden" }}>
      <MapContainer center={[40.7128, -74.006]} zoom={12} style={{ height: "100%", width: "100%" }}>
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="&copy; OpenStreetMap contributors"
        />

        {buses.map((bus) => (
          <CircleMarker
            key={bus.id}
            center={[bus.lat, bus.lon]}
            radius={6}
            color={getColor(bus.status)}
            fillOpacity={0.8}
          >
            <Popup>
              <strong>ID:</strong> {bus.id} <br />
              <strong>Status:</strong> {bus.status}
            </Popup>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Floating Panel for Chart */}
      <div style={{ position: "absolute", top: 10, right: 10, zIndex: 1000 }}>
        <button onClick={() => setShowChart(!showChart)}>
          {showChart ? "Hide Bus Chart" : "Show Bus Chart"}
        </button>
        {showChart && (
          <div
            style={{
              background: "white",
              padding: "10px",
              borderRadius: "8px",
              maxHeight: "400px",
              overflow: "auto",
              boxShadow: "0px 0px 10px rgba(0,0,0,0.3)",
            }}
          >
            <BusTrendChart buses={buses} />
          </div>
        )}
      </div>
    </div>
  );
};

export default MapComponent;
